import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useSelector, useDispatch } from 'react-redux';
import { MapPin, CreditCard, Truck, ChevronRight, Check } from 'lucide-react';
import { useCart } from '../hooks/usecart';
import { paymentAPI, orderAPI } from '../services/api';
import { initializeRazorpay } from '../services/paymentservice';
import { setCurrentOrder } from '../store/slices/orderslice';
import { clearCart } from '../store/slices/cartslice';
import LoadingSpinner from '../components/common/lodingspinner';

const CheckoutPage = () => {
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const { user } = useSelector((state) => state.auth);
  const { items, getCartTotal } = useCart();
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);

  const [address, setAddress] = useState({
    full_name: [user?.first_name, user?.last_name].filter(Boolean).join(' '),
    phone: user?.phone || '',
    line1: '',
    line2: '',
    city: '',
    state: '',
    pincode: '',
  });

  const [paymentMethod, setPaymentMethod] = useState('razorpay');
  const [useEmi, setUseEmi] = useState(false);

  const handlePlaceOrder = async () => {
    setLoading(true);
    try {
      // Create order on backend
      const orderResponse = await orderAPI.create({
        items,
        shipping_address: address,
        payment_method: paymentMethod,
        subtotal: getCartTotal(),
        emi_plan: useEmi ? { duration: 6, bank: 'HDFC' } : null,
      });

      const orderData = orderResponse.data;
      dispatch(setCurrentOrder(orderData));

      if (paymentMethod === 'razorpay') {
        // Create Razorpay order
        const paymentResponse = await paymentAPI.createOrder({
          amount: orderData.grand_total,
          receipt: orderData.order_number,
          customer_name: address.full_name,
          customer_email: user?.email,
          customer_phone: address.phone,
          address: `${address.line1}, ${address.city}`,
          emi_plan: useEmi ? { subvention_plan_id: 'plan_123' } : null,
        });

        initializeRazorpay(
          paymentResponse.data,
          async (paymentResult) => {
            // Verify payment
            await paymentAPI.verify({
              ...paymentResult,
              order_id: orderData._id,
            });
            dispatch(clearCart());
            navigate(`/order-success/${orderData.order_number}`);
          },
          (error) => {
            console.error('Payment failed:', error);
            setLoading(false);
          }
        );
      }
    } catch (error) {
      console.error('Order error:', error);
      setLoading(false);
    }
  };

  if (items.length === 0) {
    return (
      <div className="container mx-auto px-4 py-20 text-center">
        <h2 className="text-xl font-semibold mb-4">Your cart is empty</h2>
        <button
          onClick={() => navigate('/')}
          className="bg-primary-700 text-white px-6 py-2 rounded-lg"
        >
          Continue Shopping
        </button>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-6 md:py-10 max-w-6xl">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Checkout</h1>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          {/* Step 1: Address */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
            <div className="flex items-center gap-3 mb-4">
              <div
                className={`w-8 h-8 rounded-full flex items-center justify-center ${
                  step >= 1 ? 'bg-primary-700 text-white' : 'bg-gray-100'
                }`}
              >
                {step > 1 ? (
                  <Check className="w-4 h-4" />
                ) : (
                  <MapPin className="w-4 h-4" />
                )}
              </div>
              <h2 className="font-semibold">Shipping Address</h2>
            </div>

            {step === 1 && (
              <div className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <input
                    type="text"
                    placeholder="Full Name"
                    className="w-full px-4 py-2.5 border border-gray-200 rounded-lg text-sm"
                    value={address.full_name}
                    onChange={(e) =>
                      setAddress({ ...address, full_name: e.target.value })
                    }
                  />
                  <input
                    type="tel"
                    placeholder="Phone Number"
                    className="w-full px-4 py-2.5 border border-gray-200 rounded-lg text-sm"
                    value={address.phone}
                    onChange={(e) =>
                      setAddress({ ...address, phone: e.target.value })
                    }
                  />
                </div>
                <input
                  type="text"
                  placeholder="Address Line 1"
                  className="w-full px-4 py-2.5 border border-gray-200 rounded-lg text-sm"
                  value={address.line1}
                  onChange={(e) =>
                    setAddress({ ...address, line1: e.target.value })
                  }
                />
                <input
                  type="text"
                  placeholder="Address Line 2 (Optional)"
                  className="w-full px-4 py-2.5 border border-gray-200 rounded-lg text-sm"
                  value={address.line2}
                  onChange={(e) =>
                    setAddress({ ...address, line2: e.target.value })
                  }
                />
                <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                  <input
                    type="text"
                    placeholder="City"
                    className="w-full px-4 py-2.5 border border-gray-200 rounded-lg text-sm"
                    value={address.city}
                    onChange={(e) =>
                      setAddress({ ...address, city: e.target.value })
                    }
                  />
                  <input
                    type="text"
                    placeholder="State"
                    className="w-full px-4 py-2.5 border border-gray-200 rounded-lg text-sm"
                    value={address.state}
                    onChange={(e) =>
                      setAddress({ ...address, state: e.target.value })
                    }
                  />
                  <input
                    type="text"
                    placeholder="Pincode"
                    className="w-full px-4 py-2.5 border border-gray-200 rounded-lg text-sm"
                    value={address.pincode}
                    onChange={(e) =>
                      setAddress({ ...address, pincode: e.target.value })
                    }
                  />
                </div>
                <button
                  onClick={() => setStep(2)}
                  className="w-full md:w-auto bg-primary-700 text-white px-6 py-2.5 rounded-lg font-medium hover:bg-primary-800"
                >
                  Continue to Payment
                </button>
              </div>
            )}
          </div>

          {/* Step 2: Payment */}
          {step >= 2 && (
            <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
              <div className="flex items-center gap-3 mb-4">
                <div
                  className={`w-8 h-8 rounded-full flex items-center justify-center ${
                    step >= 2 ? 'bg-primary-700 text-white' : 'bg-gray-100'
                  }`}
                >
                  {step > 2 ? (
                    <Check className="w-4 h-4" />
                  ) : (
                    <CreditCard className="w-4 h-4" />
                  )}
                </div>
                <h2 className="font-semibold">Payment Method</h2>
              </div>

              {step === 2 && (
                <div className="space-y-4">
                  <div className="space-y-2">
                    <label className="flex items-center p-4 border-2 border-primary-600 bg-primary-50 rounded-lg cursor-pointer">
                      <input
                        type="radio"
                        name="payment"
                        checked={paymentMethod === 'razorpay'}
                        onChange={() => setPaymentMethod('razorpay')}
                        className="mr-3"
                      />
                      <div>
                        <p className="font-medium">Pay Online</p>
                        <p className="text-xs text-gray-500">
                          UPI, Cards, NetBanking, Wallets
                        </p>
                      </div>
                    </label>

                    <label className="flex items-center p-4 border border-gray-200 rounded-lg cursor-pointer opacity-50">
                      <input
                        type="radio"
                        name="payment"
                        disabled
                        className="mr-3"
                      />
                      <div>
                        <p className="font-medium">Cash on Delivery</p>
                        <p className="text-xs text-gray-500">
                          Currently unavailable
                        </p>
                      </div>
                    </label>
                  </div>

                  <div className="bg-amber-50 p-4 rounded-lg">
                    <label className="flex items-center gap-3 cursor-pointer">
                      <input
                        type="checkbox"
                        checked={useEmi}
                        onChange={(e) => setUseEmi(e.target.checked)}
                        className="w-4 h-4 text-primary-600"
                      />
                      <div>
                        <p className="font-medium text-sm">No Cost EMI</p>
                        <p className="text-xs text-gray-600">
                          Pay in 6 months @ 0% interest
                        </p>
                      </div>
                    </label>
                  </div>

                  <div className="flex gap-3">
                    <button
                      onClick={() => setStep(1)}
                      className="px-6 py-2.5 border border-gray-200 rounded-lg text-sm font-medium"
                    >
                      Back
                    </button>
                    <button
                      onClick={() => setStep(3)}
                      className="bg-primary-700 text-white px-6 py-2.5 rounded-lg font-medium hover:bg-primary-800"
                    >
                      Review Order
                    </button>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Step 3: Review */}
          {step >= 3 && (
            <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
              <div className="flex items-center gap-3 mb-4">
                <div className="w-8 h-8 rounded-full bg-primary-700 text-white flex items-center justify-center">
                  <Truck className="w-4 h-4" />
                </div>
                <h2 className="font-semibold">Review & Place Order</h2>
              </div>

              <div className="space-y-4">
                <div className="bg-gray-50 p-4 rounded-lg text-sm space-y-1">
                  <p className="font-medium">Delivering to:</p>
                  <p>{address.full_name}</p>
                  <p>
                    {address.line1}
                    {address.line2 ? `, ${address.line2}` : ''}
                  </p>
                  <p>
                    {address.city}, {address.state} - {address.pincode}
                  </p>
                  <p>Phone: {address.phone}</p>
                </div>

                <button
                  onClick={handlePlaceOrder}
                  disabled={loading}
                  className="w-full bg-primary-700 text-white py-3.5 rounded-xl font-semibold text-lg hover:bg-primary-800 transition flex items-center justify-center gap-2 disabled:opacity-70"
                >
                  {loading ? (
                    <LoadingSpinner size="sm" />
                  ) : (
                    <>
                      Place Order
                      <ChevronRight className="w-5 h-5" />
                    </>
                  )}
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Order Summary Sidebar */}
        <div className="lg:col-span-1">
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 sticky top-20">
            <h2 className="font-semibold text-gray-900 mb-4">Order Summary</h2>
            <div className="space-y-3 mb-4">
              {items.map((item) => (
                <div
                  key={`${item.productId}_${item.variantId}`}
                  className="flex gap-3"
                >
                  <div className="w-12 h-12 bg-gray-100 rounded overflow-hidden flex-shrink-0">
                    <img
                      src={item.image}
                      alt=""
                      className="w-full h-full object-cover"
                    />
                  </div>
                  <div className="flex-grow min-w-0">
                    <p className="text-sm font-medium truncate">{item.name}</p>
                    <p className="text-xs text-gray-500">
                      Qty: {item.quantity}
                    </p>
                  </div>
                  <p className="text-sm font-medium">
                    ₹{(item.price * item.quantity).toLocaleString()}
                  </p>
                </div>
              ))}
            </div>

            <div className="border-t border-gray-100 pt-4 space-y-2 text-sm">
              <div className="flex justify-between">
                <span className="text-gray-600">Subtotal</span>
                <span>₹{getCartTotal().toLocaleString()}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-gray-600">Shipping</span>
                <span className="text-green-600">Free</span>
              </div>
              <div className="flex justify-between">
                <span className="text-gray-600">GST</span>
                <span>
                  ₹{Math.round(getCartTotal() * 0.18).toLocaleString()}
                </span>
              </div>
            </div>

            <div className="border-t border-gray-100 pt-4 mt-4">
              <div className="flex justify-between font-bold text-lg">
                <span>Total</span>
                <span>
                  ₹{Math.round(getCartTotal() * 1.18).toLocaleString()}
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CheckoutPage;
